import { useEffect, useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { normalizeCustomerForm } from "../components/CustomerForm";
import API, { getApiError } from "../services/api";
import {
  PLAN_OPTIONS,
  formatDisplayDate,
  getMembershipState,
  getPlanEndDate
} from "../utils/membership";

export default function Customers() {
  const location = useLocation();
  const navigate = useNavigate();
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [flashMessage, setFlashMessage] = useState(location.state?.message || "");
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [editingCustomer, setEditingCustomer] = useState(null);
  const [editForm, setEditForm] = useState(null);
  const [editError, setEditError] = useState("");
  const [savingEdit, setSavingEdit] = useState(false);

  useEffect(() => {
    const loadCustomers = async () => {
      setLoading(true);
      setError("");

      try {
        const response = await API.get("/customers");
        setCustomers(response.data);
      } catch (requestError) {
        setError(getApiError(requestError, "Unable to load customers."));
      } finally {
        setLoading(false);
      }
    };

    loadCustomers();
  }, []);

  useEffect(() => {
    if (location.state?.message) {
      navigate(location.pathname, { replace: true });
    }
  }, [location.pathname, location.state, navigate]);

  const filteredCustomers = customers.filter((customer) => {
    const searchValue = query.toLowerCase().trim();
    const matchesSearch =
      !searchValue ||
      customer.fullName.toLowerCase().includes(searchValue) ||
      String(customer.customerId).includes(searchValue) ||
      customer.phone.includes(searchValue);

    const membership = getMembershipState(customer.planEnd);
    const matchesStatus =
      statusFilter === "All" ||
      (statusFilter === "Active" && membership.tone === "success") ||
      (statusFilter === "Expiring" && membership.tone === "warning") ||
      (statusFilter === "Expired" && membership.tone === "danger");

    return matchesSearch && matchesStatus;
  });

  const activeCount = customers.filter(
    (customer) => getMembershipState(customer.planEnd).tone === "success"
  ).length;
  const expiringCount = customers.filter(
    (customer) => getMembershipState(customer.planEnd).tone === "warning"
  ).length;
  const expiredCount = customers.filter(
    (customer) => getMembershipState(customer.planEnd).tone === "danger"
  ).length;
  const editPreviewEndDate =
    editingCustomer && editForm
      ? getPlanEndDate(
          editForm.planStart || new Date().toISOString().split("T")[0],
          editForm.plan
        )
      : "";

  const openEditModal = (customer) => {
    setEditingCustomer(customer);
    setEditForm(normalizeCustomerForm(customer));
    setEditError("");
  };

  const closeEditModal = (force = false) => {
    if (savingEdit && !force) {
      return;
    }

    setEditingCustomer(null);
    setEditForm(null);
    setEditError("");
  };

  const updateEditField = (key, value) => {
    setEditForm((current) => ({ ...current, [key]: value }));
  };

  const handleEditSubmit = async (event) => {
    event.preventDefault();

    if (!editingCustomer || !editForm) {
      return;
    }

    setEditError("");

    if (
      !editForm.fullName ||
      !editForm.phone ||
      !editForm.age ||
      !editForm.amountPaid ||
      !editForm.planStart ||
      !editForm.planEnd
    ) {
      setEditError("Please fill in name, phone, age, amount paid, plan start, and plan end before saving.");
      return;
    }

    if (editForm.planEnd < editForm.planStart) {
      setEditError("Plan end cannot be earlier than plan start.");
      return;
    }

    setSavingEdit(true);

    try {
      const response = await API.put(`/customers/${editingCustomer.customerId}`, {
        ...editForm,
        age: Number(editForm.age),
        amountPaid: Number(editForm.amountPaid)
      });

      setCustomers((current) =>
        current.map((customer) =>
          customer.customerId === editingCustomer.customerId ? response.data : customer
        )
      );
      setFlashMessage(`${response.data.fullName} was updated successfully.`);
      closeEditModal(true);
    } catch (requestError) {
      setEditError(getApiError(requestError, "Unable to update this customer."));
    } finally {
      setSavingEdit(false);
    }
  };

  return (
    <div className="page-stack">
      <section className="page-heading">
        <div>
          <span className="eyebrow">Member directory</span>
          <h2>Customers and plan status</h2>
          <p>Search members and check their plan status.</p>
        </div>
        <Link className="button" to="/add">
          Add another customer
        </Link>
      </section>

      {flashMessage ? (
        <div className="status-banner">
          {flashMessage}
          <button className="text-link" onClick={() => setFlashMessage("")}>
            Dismiss
          </button>
        </div>
      ) : null}

      {error ? <div className="status-banner status-banner--error">{error}</div> : null}

      <section className="summary-strip">
        <div>
          <strong>{loading ? "..." : customers.length}</strong>
          <span>Total customers</span>
        </div>
        <div>
          <strong>{loading ? "..." : activeCount}</strong>
          <span>Active</span>
        </div>
        <div>
          <strong>{loading ? "..." : expiringCount}</strong>
          <span>Expiring soon</span>
        </div>
        <div>
          <strong>{loading ? "..." : expiredCount}</strong>
          <span>Expired</span>
        </div>
      </section>

      <section className="panel-card">
        <div className="filters-row">
          <label className="field">
            <span>Search members</span>
            <input
              placeholder="Name, phone, or ID"
              value={query}
              onChange={(event) => setQuery(event.target.value)}
            />
          </label>

          <label className="field field--compact">
            <span>Status</span>
            <select
              value={statusFilter}
              onChange={(event) => setStatusFilter(event.target.value)}
            >
              <option value="All">All</option>
              <option value="Active">Active</option>
              <option value="Expiring">Expiring soon</option>
              <option value="Expired">Expired</option>
            </select>
          </label>
        </div>

        {loading ? (
          <div className="panel-empty">Loading customers...</div>
        ) : filteredCustomers.length ? (
          <div className="table-wrap">
            <table className="data-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Member</th>
                  <th>Plan</th>
                  <th>Amount</th>
                  <th>Plan ends</th>
                  <th>Last attended</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {filteredCustomers.map((customer) => {
                  const membership = getMembershipState(customer.planEnd);

                  return (
                    <tr key={customer.customerId}>
                      <td>#{customer.customerId}</td>
                      <td>
                        <div className="table-member">
                          <strong>{customer.fullName}</strong>
                          <span>
                            {customer.phone} • Age {customer.age || "N/A"}
                          </span>
                        </div>
                      </td>
                      <td>{customer.plan}</td>
                      <td>Rs. {customer.amountPaid}</td>
                      <td>{formatDisplayDate(customer.planEnd)}</td>
                      <td>{formatDisplayDate(customer.lastAttended)}</td>
                      <td>
                        <span className={`badge badge--${membership.tone}`}>
                          {membership.label}
                        </span>
                      </td>
                      <td>
                        <button
                          className="text-link"
                          type="button"
                          onClick={() => openEditModal(customer)}
                        >
                          Edit
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="panel-empty">
            No customers match the current search. Try another filter or add a
            new member.
          </div>
        )}
      </section>

      {editingCustomer && editForm ? (
        <div className="modal-backdrop" onClick={closeEditModal}>
          <div
            className="modal-card"
            onClick={(event) => event.stopPropagation()}
            role="dialog"
            aria-modal="true"
            aria-labelledby="edit-customer-title"
          >
            <div className="modal-card__header">
              <div>
                <span className="eyebrow">Member updates</span>
                <h3 id="edit-customer-title">Edit {editingCustomer.fullName}</h3>
                <p>Update the old details and save without leaving this page.</p>
              </div>
              <button
                className="modal-close-button"
                type="button"
                onClick={closeEditModal}
                aria-label="Close edit dialog"
                disabled={savingEdit}
              >
                X
              </button>
            </div>

            <form className="modal-form" onSubmit={handleEditSubmit}>
              {editError ? (
                <div className="status-banner status-banner--error">{editError}</div>
              ) : null}

              <div className="form-grid">
                <label className="field">
                  <span>Full name</span>
                  <input
                    placeholder="Enter member name"
                    value={editForm.fullName}
                    onChange={(event) => updateEditField("fullName", event.target.value)}
                  />
                </label>

                <label className="field">
                  <span>Phone number</span>
                  <input
                    placeholder="Enter phone number"
                    value={editForm.phone}
                    onChange={(event) => updateEditField("phone", event.target.value)}
                  />
                </label>

                <label className="field">
                  <span>Age</span>
                  <input
                    type="number"
                    min="1"
                    placeholder="Enter age"
                    value={editForm.age}
                    onChange={(event) => updateEditField("age", event.target.value)}
                  />
                </label>

                <label className="field">
                  <span>Amount paid</span>
                  <input
                    type="number"
                    min="0"
                    placeholder="Enter amount paid"
                    value={editForm.amountPaid}
                    onChange={(event) => updateEditField("amountPaid", event.target.value)}
                  />
                </label>
              </div>

              <label className="field">
                <span>Membership plan</span>
                <select
                  value={editForm.plan}
                  onChange={(event) => updateEditField("plan", event.target.value)}
                >
                  {PLAN_OPTIONS.map((plan) => (
                    <option key={plan} value={plan}>
                      {plan}
                    </option>
                  ))}
                </select>
              </label>

              <div className="form-grid">
                <label className="field">
                  <span>Plan start</span>
                  <input
                    type="date"
                    value={editForm.planStart}
                    onChange={(event) => updateEditField("planStart", event.target.value)}
                  />
                </label>

                <label className="field">
                  <span>Plan end</span>
                  <input
                    type="date"
                    value={editForm.planEnd}
                    onChange={(event) => updateEditField("planEnd", event.target.value)}
                  />
                  <button
                    className="text-link"
                    type="button"
                    onClick={() => updateEditField("planEnd", editPreviewEndDate)}
                  >
                    Use suggested end date
                  </button>
                </label>
              </div>

              <label className="field">
                <span>Last attended</span>
                <input
                  type="date"
                  value={editForm.lastAttended}
                  onChange={(event) => updateEditField("lastAttended", event.target.value)}
                />
                <button
                  className="text-link"
                  type="button"
                  onClick={() => updateEditField("lastAttended", "")}
                >
                  Clear date
                </button>
              </label>

              <div className="modal-summary">
                <div className="info-card__row">
                  <span>Customer ID</span>
                  <strong>#{editingCustomer.customerId}</strong>
                </div>
                <div className="info-card__row">
                  <span>Plan start</span>
                  <strong>{formatDisplayDate(editForm.planStart)}</strong>
                </div>
                <div className="info-card__row">
                  <span>Plan end</span>
                  <strong>{formatDisplayDate(editForm.planEnd)}</strong>
                </div>
                <div className="info-card__row">
                  <span>Last attended</span>
                  <strong>{formatDisplayDate(editForm.lastAttended)}</strong>
                </div>
                <div className="info-card__row">
                  <span>Suggested end date</span>
                  <strong>{formatDisplayDate(editPreviewEndDate)}</strong>
                </div>
              </div>

              <div className="form-actions">
                <button className="button" type="submit" disabled={savingEdit}>
                  {savingEdit ? "Saving..." : "Save changes"}
                </button>
                <button
                  className="button button--ghost"
                  type="button"
                  onClick={closeEditModal}
                  disabled={savingEdit}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      ) : null}
    </div>
  );
}
